INSERT INTO `ai_chat_logs` VALUES (1,2,'kaplв”Җв–’ca hakkв”Җв–’nda bilgi ver','в”ңГ§ermik Kaplв”Җв–’calarв”Җв–’ hakkв”Җв–’nda bilgi: в”Җв–‘lв”ңДҹemizin Tarihi ve Turistik Yerleri\r\nв”ңГ§ermik Melike Belkв”Җв–’s Kaplв”Җв–’calarв”Җв–’:  в”Җв–‘lв”ңДҹe merkezinin Hamambaв”јЕҹв”Җв–’ mevkiinde bulunan Melike Belkв”Җв–’s Kaplв”Җв–’calarв”Җв–’, tedavi в”ңГӮzellikleri ve niteliв”ҖЕҹi bakв”Җв–’mв”Җв–’ndan dв”ңв•қnyanв”Җв–’n en iyi kaplв”Җв–’calarв”Җв–’ndan biri olup tarihin в”ңДҹok eski dв”ңГӮnemlerinden beri insanlв”Җв–’в”ҖЕҹa в”јЕҹifa daв”ҖЕҹв”Җв–’tmaya devam etmektedir. \r\nBв”ңв•қyв”ңв•қk Paв”јЕҹaГ”ГҮГҳ ve Г”ГҮВЈKв”ңв•қв”ңДҹв”ңв•қk Paв”јЕҹaГ”ГҮГҳ denilen tarihi hamamlarв”Җв–’n yanв”Җв–’nda iki adet localв”Җв–’ ve bir adet Г”ГҮВЈв”ңГ»zel Aile KabinleriГ”ГҮГҳ olmak в”ңв•қzere beв”јЕҹ ayrв”Җв–’ bв”ңГӮlв”ңв•қmde hizmet verilmektedir. в”ңГ§ermik Melike Belkв”Җв–’s Kaplв”Җв–’calarв”Җв–’ dв”ңГӮrt mevsim hizmete aв”ңДҹв”Җв–’ktв”Җв–’r. Tedavi amaв”ңДҹlв”Җв–’ ku... (Detaylв”Җв–’ bilgi iв”ңДҹin sayfanв”Җв–’n altв”Җв–’ndaki tarihв”ңДҹe kв”Җв–’smв”Җв–’na bakabilirsiniz)','2026-02-24 08:24:55'),(2,2,'в”ңДҹermikin neresinde kalв”Җв–’yor','в”јЕһu an Ulu Cami в”ңДҹok yakв”Җв–’nв”Җв–’ndasв”Җв–’nв”Җв–’z. Ulu Cami: в”Җв–‘lв”ңДҹenin batв”Җв–’sв”Җв–’ndaki Kale MahallesiГ”ГҮГ–nde bulunmaktadв”Җв–’r. Yapв”Җв–’ ayrв”Җв–’ zamanlarda inв”јЕҹa edilmiв”јЕҹ, bitiв”јЕҹik iki camiden oluв”јЕҹmaktadв”Җв–’r. Batв”Җв–’ kesimi ilk yapв”Җв–’dan kalmв”Җв–’в”јЕҹ, doв”ҖЕҹudaki tek kubbeli kв”Җв–’sв”Җв–’m ise sonradan ilave edilmiв”јЕҹtir. Doв”ҖЕҹudan batв”Җв–’ya doв”ҖЕҹru uzanan в”ңв•қв”ңДҹ tonoz ile в”ңв•қzeri kaplв”Җв–’ olan Ulu Cami, в”ңв•қв”ңДҹer keme','2026-02-25 06:58:11'),(3,2,'bana в”ңГӮmer halis demir parkв”Җв–’nв”Җв–’ anlat','в”јЕһu an Ulu Cami в”ңДҹok yakв”Җв–’nв”Җв–’ndasв”Җв–’nв”Җв–’z. Ulu Cami: в”Җв–‘lв”ңДҹenin batв”Җв–’sв”Җв–’ndaki Kale MahallesiГ”ГҮГ–nde bulunmaktadв”Җв–’r. Yapв”Җв–’ ayrв”Җв–’ zamanlarda inв”јЕҹa edilmiв”јЕҹ, bitiв”јЕҹik iki camiden oluв”јЕҹmaktadв”Җв–’r. Batв”Җв–’ kesimi ilk yapв”Җв–’dan kalmв”Җв–’в”јЕҹ, doв”ҖЕҹudaki tek kubbeli kв”Җв–’sв”Җв–’m ise sonradan ilave edilmiв”јЕҹtir. Doв”ҖЕҹudan batв”Җв–’ya doв”ҖЕҹru uzanan в”ңв•қв”ңДҹ tonoz ile в”ңв•қzeri kaplв”Җв–’ olan Ulu Cami, в”ңв•қв”ңДҹer keme','2026-02-25 06:58:53'),(4,2,'acв”Җв–’ktв”Җв–’m','в”јЕһu an Sinek в”ңГ§ayв”Җв–’ в”јЕһelalesi sayfasв”Җв–’ndasв”Җв–’nв”Җв–’z. Bu mekan hakkв”Җв–’nda size her в”јЕҹeyi anlatabilirim. Yerel bir dost gibi konuв”јЕҹ. Piknik alanlarв”Җв–’ ve en iyi yв”ңв•қzme noktalarв”Җв–’nв”Җв–’ в”ңГӮner.','2026-02-25 09:11:37'),(5,2,'sinek в”јЕҹelalesini anlat','в”јЕһu an Ulu Cami в”ңДҹok yakв”Җв–’nв”Җв–’ndasв”Җв–’nв”Җв–’z. Ulu Cami: в”Җв–‘lв”ңДҹenin batв”Җв–’sв”Җв–’ndaki Kale MahallesiГ”ГҮГ–nde bulunmaktadв”Җв–’r. Yapв”Җв–’ ayrв”Җв–’ zamanlarda inв”јЕҹa edilmiв”јЕҹ, bitiв”јЕҹik iki camiden oluв”јЕҹmaktadв”Җв–’r. Batв”Җв–’ kesimi ilk yapв”Җв–’dan kalmв”Җв–’в”јЕҹ, doв”ҖЕҹudaki tek kubbeli kв”Җв–’sв”Җв–’m ise sonradan ilave edilmiв”јЕҹtir. Doв”ҖЕҹudan batв”Җв–’ya doв”ҖЕҹru uzanan в”ңв•қв”ңДҹ tonoz ile в”ңв•қzeri kaplв”Җв–’ olan Ulu Cami, в”ңв•қв”ңДҹer keme','2026-02-25 09:11:53');
