INSERT INTO `genel_bilgiler` VALUES (1,'Hв”ңв•қkв”ңв•қmet Konaв”ҖЕҹв”Җв–’ ','Geliв”јЕҹtirdiв”ҖЕҹin в”ңГ§ermik ilв”ңДҹe rehberi uygulamasв”Җв–’ iв”ңДҹin \"Resmi Kurumlar\" veya \"в”ңГ»nemli Yerler\" kategorisinde kullanabileceв”ҖЕҹin в”ңГ§ermik Hв”ңв•қkв”ңв•қmet Konaв”ҖЕҹв”Җв–’ hakkв”Җв–’ndaki detaylв”Җв–’ konum ve kurum bilgilerini aв”јЕҹaв”ҖЕҹв”Җв–’da derledim:\r\n\r\nKonum ve Adres Bilgisi\r\nв”ңГ§ermik Hв”ңв•қkв”ңв•қmet Konaв”ҖЕҹв”Җв–’, vatandaв”јЕҹlarв”Җв–’n kolayca ulaв”јЕҹabilmesi iв”ңДҹin ilв”ңДҹe merkezinde, oldukв”ңДҹa iв”јЕҹlek bir noktada yer almaktadв”Җв–’r.\r\n\r\nAв”ңДҹв”Җв–’k Adres: Tepe Mahallesi, Diyarbakв”Җв–’r Caddesi, Hв”ңв•қkв”ңв•қmet Konaв”ҖЕҹв”Җв–’ Binasв”Җв–’, 21600 в”ңГ§ermik / Diyarbakв”Җв–’r\r\n(Not: Binanв”Җв–’n konumu Tepe ve в”ңГ§ukur mahallelerinin kesiв”јЕҹim noktasв”Җв–’na в”ңДҹok yakв”Җв–’ndв”Җв–’r, resmi kayв”Җв–’tlarda bazв”Җв–’ birimler в”ңГ§ukur Mah. Kapalв”Җв–’ Sokak olarak da geв”ңДҹebilmektedir ancak ana giriв”јЕҹ ve bilinen adres Tepe Mah. Diyarbakв”Җв–’r Caddesi в”ңв•қzerindedir.)\r\n\r\nHв”ңв•қkв”ңв•қmet Konaв”ҖЕҹв”Җв–’ в”Җв–‘в”ңДҹerisinde Hizmet Veren Kurumlar\r\nв”Җв–‘lв”ңДҹedeki resmi idari iв”јЕҹlerin tek merkezden yв”ңв•қrв”ңв•қtв”ңв•қlebilmesi amacв”Җв–’yla birв”ңДҹok mв”ңв•қdв”ңв•қrlв”ңв•қk bu binanв”Җв–’n iв”ңДҹinde (veya ek binasв”Җв–’nda) toplanmв”Җв–’в”јЕҹtв”Җв–’r. Bina iв”ңДҹerisinde yer alan baв”јЕҹlв”Җв–’ca kamu kurumlarв”Җв–’ в”јЕҹunlardв”Җв–’r:\r\n\r\n1. в”ңГ§ermik Kaymakamlв”Җв–’в”ҖЕҹв”Җв–’ ve Baв”ҖЕҹlв”Җв–’ Birimler:\r\n\r\nKaymakamlв”Җв–’k Makamв”Җв–’ ve в”Җв–‘lв”ңДҹe Yazв”Җв–’ в”Җв–‘в”јЕҹleri Mв”ңв•қdв”ңв•қrlв”ңв•қв”ҖЕҹв”ңв•қ: в”Җв–‘lв”ңДҹenin genel idaresi, resmi yazв”Җв–’в”јЕҹmalar ve vatandaв”јЕҹ dilekв”ңДҹelerinin kabul edildiв”ҖЕҹi ana birim.\r\n\r\nв”Җв–‘lв”ңДҹe Sosyal Yardв”Җв–’mlaв”јЕҹma ve Dayanв”Җв–’в”јЕҹma Vakfв”Җв–’ (SYDV): в”Җв–‘htiyaв”ңДҹ sahibi vatandaв”јЕҹlara yakacak, barв”Җв–’nma, eв”ҖЕҹitim, saв”ҖЕҹlв”Җв–’k ve nakdi yardв”Җв–’mlarв”Җв–’n koordine edildiв”ҖЕҹi merkez.\r\n\r\nв”Җв–‘lв”ңДҹe Malmв”ңв•қdв”ңв•қrlв”ңв•қв”ҖЕҹв”ңв•қ: Hazine ve maliye iв”јЕҹlemleri, vezne ve tahsilat hizmetlerinin yв”ңв•қrв”ңв•қtв”ңв•қldв”ңв•қв”ҖЕҹв”ңв•қ birim.\r\n\r\n2. Diв”ҖЕҹer Temel Kamu Kurumlarв”Җв–’:\r\n\r\nв”ңГ§ermik в”Җв–‘lв”ңДҹe Nв”ңв•қfus Mв”ңв•қdв”ңв•қrlв”ңв•қв”ҖЕҹв”ңв•қ: Kimlik, pasaport, sв”ңв•қrв”ңв•қcв”ңв•қ belgesi, adres kayв”Җв–’t ve doв”ҖЕҹum/в”ңГӮlв”ңв•қm/evlilik tescil iв”јЕҹlemlerinin yapв”Җв–’ldв”Җв–’в”ҖЕҹв”Җв–’ en yoв”ҖЕҹun kurumlardan biridir.\r\n\r\nв”ңГ§ermik Adliyesi: Hв”ңв•қkв”ңв•қmet Konaв”ҖЕҹв”Җв–’ yapв”Җв–’sв”Җв–’ iв”ңДҹerisinde (veya entegre bitiв”јЕҹik nizamda) hizmet verir. Adli makamlar, savcв”Җв–’lв”Җв–’k ve mahkeme salonlarв”Җв–’ burada bulunur.\r\n\r\nв”Җв–‘lв”ңДҹe Seв”ңДҹim Kurulu Baв”јЕҹkanlв”Җв–’в”ҖЕҹв”Җв–’: Seв”ңДҹim dв”ңГӮnemlerinde ve seв”ңДҹmen kв”ңв•қtв”ңв•қв”ҖЕҹв”ңв•қ iв”јЕҹlemlerinde aktif olan birimdir (Adliye ile koordineli в”ңДҹalв”Җв–’в”јЕҹв”Җв–’r).\r\n\r\n(Not: в”Җв–‘lв”ңДҹe Emniyet Mв”ңв•қdв”ңв•қrlв”ңв•қв”ҖЕҹв”ңв•қ, в”Җв–‘lв”ңДҹe Milli Eв”ҖЕҹitim Mв”ңв•қdв”ңв•қrlв”ңв•қв”ҖЕҹв”ңв•қ veya в”Җв–‘lв”ңДҹe Tarв”Җв–’m Mв”ңв•қdв”ңв•қrlв”ңв•қв”ҖЕҹв”ңв•қ gibi bazв”Җв–’ kurumlar, kapasite veya gв”ңГӮrev alanlarв”Җв–’ gereв”ҖЕҹi ilв”ңДҹenin farklв”Җв–’ noktalarв”Җв–’ndaki kendi mв”ңв•қstakil binalarв”Җв–’nda hizmet verebilmektedir. Kaymakamlв”Җв–’в”ҖЕҹa baв”ҖЕҹlв”Җв–’ olsalar da fiziki olarak her zaman Hв”ңв•қkв”ңв•қmet Konaв”ҖЕҹв”Җв–’\'nв”Җв–’n iв”ңДҹinde yer almazlar.)','2026-02-23 12:57:44');
