INSERT INTO `hospitals` VALUES (1,'в”ңГ§ermik Devlet Hastanesi','Genel Kapasite ve Yeni Hizmet Binasв”Җв–’\r\nYeni Hastane Binasв”Җв–’: Hastane, Aв”ҖЕҹustos 2024\'te 18.810 metrekarelik kapalв”Җв–’ alana sahip yeni ve modern binasв”Җв–’na taв”јЕҹв”Җв–’narak 50 yatak kapasitesiyle hizmet vermeye baв”јЕҹlamв”Җв–’в”јЕҹtв”Җв–’r. Eski binasв”Җв–’ndan taв”јЕҹв”Җв–’ndв”Җв–’в”ҖЕҹв”Җв–’ iв”ңДҹin gв”ңв•қncel adresi deв”ҖЕҹiв”јЕҹmiв”јЕҹtir.\r\n\r\nKapasite Detaylarв”Җв–’: 25 poliklinik odasв”Җв–’, 3 ameliyathane, 20\'si tek kiв”јЕҹilik ve 15\'i в”ңДҹift kiв”јЕҹilik olmak в”ңв•қzere toplam 35 hasta odasв”Җв–’ ile hasta kabul etmektedir.\r\n\r\nYoв”ҖЕҹun Bakв”Җв–’m ve в”ңВЈniteler: 4 yataklв”Җв–’ yenidoв”ҖЕҹan yoв”ҖЕҹun bakв”Җв–’m, 6 yataklв”Җв–’ genel yoв”ҖЕҹun bakв”Җв–’m, 7 cihazlв”Җв–’ hemodiyaliz в”ңв•қnitesi ve 10 hasta kapasiteli fizik tedavi в”ңв•қnitesi mevcuttur.\r\n\r\n2026 Yв”Җв–’lв”Җв–’ndaki в”ңГ»nemli Geliв”јЕҹmeler\r\nAnne Dostu Hastane Unvanв”Җв–’ (Ocak 2026): Hastane, Saв”ҖЕҹlв”Җв–’k Bakanlв”Җв–’в”ҖЕҹв”Җв–’ tarafв”Җв–’ndan yapв”Җв–’lan deв”ҖЕҹerlendirmeler sonucunda anne ve bebek saв”ҖЕҹlв”Җв–’в”ҖЕҹв”Җв–’nв”Җв–’ в”ңГӮnceleyen standartlarв”Җв–’ baв”јЕҹarв”Җв–’yla karв”јЕҹв”Җв–’layarak \"Anne Dostu Hastane\" unvanв”Җв–’nв”Җв–’ aldв”Җв–’. в”ңГ§ermik Devlet Hastanesi, 2026 yв”Җв–’lв”Җв–’nda Tв”ңв•қrkiye genelinde bu unvanв”Җв–’ almaya hak kazanan ilk saв”ҖЕҹlв”Җв–’k tesisi oldu.\r\n\r\nBaв”јЕҹhekim Deв”ҖЕҹiв”јЕҹikliв”ҖЕҹi (в”јЕһubat 2026): в”јЕһubat 2026 baв”јЕҹlarв”Җв–’nda hastane baв”јЕҹhekimliв”ҖЕҹine Umut Karagв”ңГӮz\'в”ңв•қn yerine Fв”Җв–’rat Tв”ңв•қrken atanmв”Җв–’в”јЕҹtв”Җв–’r.\r\n\r\nв”ңГ»ne в”ңГ§в”Җв–’kan Hizmetler ve Donanв”Җв–’mlar\r\nHastane, yenidoв”ҖЕҹan sarв”Җв–’lв”Җв–’в”ҖЕҹв”Җв–’ tedavisini hв”Җв–’zlandв”Җв–’ran tв”ңв•қnel fototerapi cihazlarв”Җв–’ ve mide/baв”ҖЕҹв”Җв–’rsak hastalв”Җв–’klarв”Җв–’nв”Җв–’n teв”јЕҹhisi iв”ңДҹin kurulan endoskopi/kolonoskopi в”ңв•қniteleriyle bв”ңГӮlge halkв”Җв–’na geliв”јЕҹmiв”јЕҹ tв”Җв–’bbi imkanlar sunmaktadв”Җв–’r.\r\n\r\n5 yatak kapasiteli evde saв”ҖЕҹlв”Җв–’k hizmeti birimi de aktif olarak bв”ңГӮlge halkв”Җв–’na destek vermektedir.\r\n\r\nGв”ңв•қncel в”Җв–‘letiв”јЕҹim ve Adres Bilgileri\r\n(в”ңГ»nemli Not: Eski \"Siverek Yolu\" adresi yeni binayla birlikte deв”ҖЕҹiв”јЕҹmiв”јЕҹtir.)\r\n\r\nAdres: Tepe Mahallesi, Diyarbakв”Җв–’r Caddesi No:128 в”ңГ§ermik / Diyarbakв”Җв–’r\r\n\r\nTelefon: 0 (412) 606 05 74\r\n\r\nE-posta: dbkrcermikdh.bsh@saglik.gov.tr',38.14381625,39.47553181,'','uploads/hospital_1772196367.jpeg','2026-02-23 08:43:00','',''),(2,'в”ңГ§ermik 1 Nolu Saв”ҖЕҹlв”Җв–’k Ocaв”ҖЕҹв”Җв–’','',38.13589309,39.45398365,'','','2026-02-23 08:51:44',NULL,NULL),(3,'в”ңГ§ermik 2 Nolu Saв”ҖЕҹlв”Җв–’k Ocaв”ҖЕҹв”Җв–’','',38.13757291,39.46782466,'','','2026-02-23 08:51:55',NULL,NULL),(4,'в”ңГ§ermik 3 Nolu Saв”ҖЕҹlв”Җв–’k Ocaв”ҖЕҹв”Җв–’','',38.13485516,39.44729905,'','','2026-02-24 09:24:23',NULL,NULL);
