INSERT INTO `municipal_guide` VALUES (1,NULL,'Evlendirme в”Җв–‘в”јЕҹleri','Evlilik baв”јЕҹvurusunda gerekli belgeler;\r\n\r\n1. Resimli Nв”ңв•қfus cв”ңв•қzdanlarв”Җв–’ aslв”Җв–’ ve fotokopileri.  10 yв”Җв–’lв”Җв–’ geв”ңДҹen nв”ңв•қfus cв”ңв•қzdanlarв”Җв–’ geв”ңДҹersizdir.Kabul edilmeyecektir.\r\n\r\n2. в”ңГ§iftlerden birinin  Belediye sв”Җв–’nв”Җв–’rlarв”Җв–’ iв”ңДҹerisinde ikamet etmesi zorunludur.\r\n\r\n3. Son 6 ayda в”ңДҹekilmiв”јЕҹ 4er adet vesikalв”Җв–’k fotoв”ҖЕҹraf. FOTOKOPв”Җв–‘ RESв”Җв–‘MLER GEв”ңГ§ERSв”Җв–‘ZDв”Җв–‘R.\r\n\r\n4. 16 yaв”јЕҹв”Җв–’nв”Җв–’ doldurup , 17 sinden gв”ңв•қn alan adaylar Aile Mahkemesinden evlenme izin belgesi 17 yaв”јЕҹв”Җв–’nв”Җв–’ bitirip 18 yaв”јЕҹв”Җв–’ndan gв”ңв•қn alan adaylar noterden alв”Җв–’nmв”Җв–’в”јЕҹ anne-baba muvafakatnamesi ile evlenebilirler.(Anne veya babadan biri в”ңГӮlmв”ңв•қв”јЕҹ ise в”ңГӮlв”ңв•қmв”ңв•қ nв”ңв•қfus kaydв”Җв–’ ile belgelenecektir).beraber gelmeleri zorunludur.\r\n\r\n5. Kayв”Җв–’t ve mв”ңв•қracaatlar sabah 08.30-16.00 saatleri arasв”Җв–’nda yapв”Җв–’lв”Җв–’r.Mв”ңв•қracaat sonrasв”Җв–’nda,hazв”Җв–’rlanacak evraklar bir sonraki gв”ңв•қn baв”јЕҹvurunun yapв”Җв–’ldв”Җв–’в”ҖЕҹв”Җв–’ ilgilidentemin edilir.Temin edilen evraklarda istenilen hususlar yerine getirilerek Nikah saati iв”ңДҹin gerekli baв”јЕҹvuru Yazв”Җв–’ в”Җв–‘в”јЕҹleri Mв”ңв•қdв”ңв•қrlв”ңв•қв”ҖЕҹв”ңв•қ\'ne yapв”Җв–’lв”Җв–’r.\r\n\r\n6.Belediye Meclisinin ...... Tarih ve ....... Sayв”Җв–’lв”Җв–’ kararв”Җв–’ gereв”ҖЕҹi:\r\n\r\nNikah akdi в”ңв•қcreti:\r\nBelediye de yapв”Җв–’lan nikah akdi в”ңв•қcreti:\r\nCв”ңв•қzdan Bedeli    ............TL\r\n \r\n\r\nMal ayrв”Җв–’lв”Җв–’в”ҖЕҹв”Җв–’ talebi olanlarв”Җв–’n, noterden yaptв”Җв–’rmв”Җв–’в”јЕҹ olduklarв”Җв–’ MAL AYRILIв”ҖЕһI Sв”ңГ»ZLEв”јЕһMESв”Җв–‘ mв”ңв•қracaat dosyasв”Җв–’na koyulur.\r\n \r\n\r\nKв”Җв–’zlв”Җв–’k soyadв”Җв–’nв”Җв–’ kullanmak isteyenler, mв”ңв•қracaat anв”Җв–’nda ilgili memura talebini bildireceklerdir.\r\n\r\nMв”ңВЈRACAAT EVRAKLARI, ALINDIв”ҖЕһI TARв”Җв–‘HTEN в”Җв–‘Tв”Җв–‘BAREN 6 AY Sв”ңВЈRE в”Җв–‘LE GEв”ңГ§ERLв”Җв–‘Dв”Җв–‘R.\r\n\r\nYabancв”Җв–’ Uyruklu Vatandaв”јЕҹlar iв”ңДҹin alв”Җв–’nacak belgeler hakkв”Җв–’nda Yazв”Җв–’ в”Җв–‘в”јЕҹleri Mв”ңв•қdв”ңв•қrlв”ңв•қв”ҖЕҹв”ңв•қ 543 23 20 (216)  no\'lu telefonlardan bilgi alв”Җв–’nabilir.\r\n\r\nв”Җв–‘stenilen evraklar tamamlandв”Җв–’ktan sonra gв”ңв•қn iв”ңДҹin mв”ңв•қracaat edilecektir.Eksik evrakla mв”ңв•қracaat yasa gereв”ҖЕҹi kabul edilmemektedir.\r\n\r\nEVLв”Җв–‘Lв”Җв–‘K BAв”јЕһVURU EVRAKLARI Dв”ңВЈZENLENDв”Җв–‘в”ҖЕһв”Җв–‘ TARв”Җв–‘HTEN в”Җв–‘Tв”Җв–‘BAREN 6 (ALTI AY) Sв”ңВЈRE  в”Җв–‘LE GEв”ңГ§ERLв”Җв–‘ OLDUв”ҖЕһUNDAN  в”Җв–‘STENв”Җв–‘LEN  Nв”Җв–‘KAH Gв”ңВЈNв”ңВЈ BU TARв”Җв–‘H ARALIв”ҖЕһINI  GEв”ңГ§MEYECEKTв”Җв–‘R.\r\n\r\nNikah в”јЕҹahitlerinin evlenecek kiв”јЕҹileri tanв”Җв–’masв”Җв–’ ve T.C. Kimlik numaralarв”Җв–’nв”Җв–’n bildirilmesi zorunludur.','',1,'2026-02-24 08:44:35',NULL,NULL),(2,NULL,'в”Җв–‘mar в”Җв–‘в”јЕҹleri','MADDE 1 Г”ГҮГҙ (1) Bu Yв”ңГӮnetmeliв”ҖЕҹin amacв”Җв–’; Ankara Bв”ңв•қyв”ңв•қkв”јЕҹehir Belediyesi sв”Җв–’nв”Җв–’rlarв”Җв–’ iв”ңДҹerisinde plan, fen, saв”ҖЕҹlв”Җв–’k ve sв”ңв•қrdв”ңв•қrв”ңв•қlebilir в”ңДҹevre в”јЕҹartlarв”Җв–’na uygun yapв”Җв–’ ve yapв”Җв–’laв”јЕҹma ile projelendirmeye ve denetime iliв”јЕҹkin usul ve esaslarв”Җв–’ belirlemektir.\r\n\r\nKapsam\r\n\r\nMADDE 2 Г”ГҮГҙ (1) Bu Yв”ңГӮnetmelik, uygulama imar planв”Җв–’ bulunan alanlarв”Җв–’ kapsar.\r\n\r\nDayanak\r\n\r\nMADDE 3 Г”ГҮГҙ (Deв”ҖЕҹiв”јЕҹik:RG-4/3/2022-31768)\r\n\r\n(1) Bu Yв”ңГӮnetmelik, 3/5/1985 tarihli ve 3194 sayв”Җв–’lв”Җв–’ в”Җв–‘mar Kanunu, 10/7/2018 tarihli ve 30474 sayв”Җв–’lв”Җв–’ Resmв”ңВ« GazeteГ”ГҮГ–de yayв”Җв–’mlanan 1 sayв”Җв–’lв”Җв–’ Cumhurbaв”јЕҹkanlв”Җв–’в”ҖЕҹв”Җв–’ Teв”јЕҹkilatв”Җв–’ Hakkв”Җв–’nda Cumhurbaв”јЕҹkanlв”Җв–’в”ҖЕҹв”Җв–’ Kararnamesinin altв”Җв–’ncв”Җв–’ kв”Җв–’smв”Җв–’nв”Җв–’n dв”ңГӮrdв”ңв•қncв”ңв•қ bв”ңГӮlв”ңв•қm hв”ңв•қkв”ңв•қmleri ile 3/7/2017 tarihli ve 30113 sayв”Җв–’lв”Җв–’ Resmв”ңВ« GazeteГ”ГҮГ–de yayв”Җв–’mlanan Planlв”Җв–’ Alanlar в”Җв–‘mar Yв”ңГӮnetmeliв”ҖЕҹinin 69 uncu maddesi hв”ңв•қkв”ңв•қmlerine dayanв”Җв–’larak hazв”Җв–’rlanmв”Җв–’в”јЕҹtв”Җв–’r.\r\n\r\nTanв”Җв–’mlar\r\n\r\nMADDE 4 Г”ГҮГҙ (Deв”ҖЕҹiв”јЕҹik:RG-4/3/2022-31768)\r\n\r\n(1) Planlв”Җв–’ Alanlar в”Җв–‘mar Yв”ңГӮnetmeliв”ҖЕҹinin 4 в”ңв•қncв”ңв•қ maddesinin birinci fв”Җв–’krasв”Җв–’nda yer alan tanв”Җв–’mlarв”Җв–’n yanв”Җв–’ sв”Җв–’ra bu Yв”ңГӮnetmelikte geв”ңДҹen;\r\n\r\na) Belediye hizmet alanв”Җв–’: Belediyelerin gв”ңГӮrev ve sorumluluklarв”Җв–’ kapsamв”Җв–’ndaki hizmetlerinin gв”ңГӮtв”ңв•қrв”ңв•қlebilmesi iв”ңДҹin gerekli itfaiye, acil yardв”Җв–’m ve kurtarma, ulaв”јЕҹв”Җв–’ma yв”ңГӮnelik transfer istasyonu, araв”ңДҹ ve makine parkв”Җв–’, bakв”Җв–’m ve ikmal istasyonu, garaj ve triyaj alanlarв”Җв–’, belediye depolarв”Җв–’, asfalt tesisi, atв”Җв–’k iв”јЕҹleme tesisi, zabв”Җв–’ta birimleri, mezbaha, ekmek в”ңв•қretim tesisi, pazar yeri, idari, sosyal ve kв”ңв•қltв”ңв•қrel merkez gibi mahallв”ңВ« mв”ңв•қв”јЕҹterek nitelikteki ihtiyaв”ңДҹlarв”Җв–’ karв”јЕҹв”Җв–’lamak в”ңв•қzere kurulan tesisler ile sermayesinin yarв”Җв–’dan fazlasв”Җв–’ belediyeye ait olan в”јЕҹirketlerin sahip olduв”ҖЕҹu tesislerin yapв”Җв–’labileceв”ҖЕҹi alanlarв”Җв–’,\r\n\r\nb) Bв”ңГӮlge kat nizamв”Җв–’ planlв”Җв–’ alanlar/bв”ңГӮlgeler: Herman Jansen ve Yв”ңв•қcel Uybadin imar planlarв”Җв–’ ile в”Җв–’slah imar planlarв”Җв–’nda; yapв”Җв–’laв”јЕҹma ile ilgili koв”јЕҹullarв”Җв–’n genellikle kat sayв”Җв–’sв”Җв–’ ve cephe hattв”Җв–’ ile belirlendiв”ҖЕҹi, bunun dв”Җв–’в”јЕҹв”Җв–’nda diв”ҖЕҹer yapв”Җв–’lanma в”јЕҹartlarв”Җв–’nda bu Yв”ңГӮnetmelik hв”ңв•қkв”ңв•қmlerinin geв”ңДҹerli olduв”ҖЕҹu (klasik parselli) alanlarв”Җв–’/bв”ңГӮlgeleri,\r\n\r\nc) Depolama alanlarв”Җв–’: в”Җв–‘mar planlarв”Җв–’nda her tв”ңв•қrlв”ңв•қ aв”ңДҹв”Җв–’k ve kapalв”Җв–’ depolama alanlarв”Җв–’, yв”ңв•қkleme-boв”јЕҹaltma-nakliye tesisleri ile depolama tesislerine ayrв”Җв–’lmв”Җв–’в”јЕҹ alanlarв”Җв–’,\r\n\r\nв”ңДҹ) Islah imar planв”Җв–’ alanlarв”Җв–’: 2805, 2981, 3290, 3366 sayв”Җв–’lв”Җв–’ Kanunlara gв”ңГӮre в”Җв–’slah imar planв”Җв–’ yapв”Җв–’lmв”Җв–’в”јЕҹ alanlarв”Җв–’,\r\n\r\nd) Kentsel servis alanlarв”Җв–’: 1/10/2017 tarihinden в”ңГӮnceki mevcut в”Җв–‘mar planlarв”Җв–’nda kentin tanв”Җв–’mlanmв”Җв–’в”јЕҹ yв”ңГӮn ve bв”ңГӮlgelerinde, bв”ңГӮlgesel ihtiyacв”Җв–’ karв”јЕҹв”Җв–’lamak в”ңв•қzere belirlenmiв”јЕҹ, bв”ңв•қro, iв”јЕҹ hanв”Җв–’, gazino, lokanta, в”ңДҹarв”јЕҹв”Җв–’, в”ңДҹok katlв”Җв–’ maв”ҖЕҹaza, banka, otel, sinema, tiyatro gibi sosyal kв”ңв•қltв”ңв•қrel tesisler, yв”ңГӮnetimle ilgili tesisler, ilgili kurumlardan uygun gв”ңГӮrв”ңв•қв”јЕҹ alв”Җв–’nmak kaydв”Җв–’yla в”ңГӮzel/resmi eв”ҖЕҹitim, saв”ҖЕҹlв”Җв–’k ve benzeri tesislerin yapв”Җв–’labildiв”ҖЕҹi alanlarв”Җв–’,\r\n\r\ne) Kentsel tasarв”Җв–’m projesi: Doв”ҖЕҹal, tarihi, kв”ңв•қltв”ңв•қrel, sosyal ve ekonomik в”ңГӮzellikler ile arazi yapв”Җв–’sв”Җв–’ dikkate alв”Җв–’narak, tasarв”Җв–’m amacв”Җв–’na gв”ңГӮre kв”ңв•қtle ve yapв”Җв–’lanma dв”ңв•қzeni veya aв”ңДҹв”Җв–’k alan dв”ңв•қzenlemelerini iв”ңДҹeren; taв”јЕҹв”Җв–’t ulaв”јЕҹв”Җв–’mв”Җв–’, otopark ve servis iliв”јЕҹkileri ve yaya dolaв”јЕҹв”Җв–’m iliв”јЕҹkilerini kuran; yapв”Җв–’, sokak, doku, aв”ңДҹв”Җв–’k ve yeв”јЕҹil alanlarв”Җв–’n iliв”јЕҹkisini ve kentsel mobilya detaylarв”Җв–’nв”Җв–’ gв”ңГӮsteren; altyapв”Җв–’ unsurlarв”Җв–’nв”Җв–’ bв”ңв•қtв”ңв•қncв”ңв•қl bir yaklaв”јЕҹв”Җв–’mla disiplinler arasв”Җв–’ olarak ele alan; imge, anlam ve kimlik в”ңГӮzelliklerini ifade eden; tasarв”Җв–’m ilke ve araв”ңДҹlarв”Җв–’nв”Җв–’ iв”ңДҹeren uygun в”ңГӮlв”ңДҹekteki projeyi,\r\n\r\nf) Kв”ңв•қв”ңДҹв”ңв•қk sanayi alanв”Җв–’: в”јЕһehirde yaв”јЕҹayanlarв”Җв–’n gв”ңв•қnlв”ңв•қk bakв”Җв–’m, tamir, servis ve kв”ңв•қв”ңДҹв”ңв•қk в”ңГӮlв”ңДҹekli imalat ihtiyaв”ңДҹlarв”Җв–’nв”Җв–’n karв”јЕҹв”Җв–’lanabileceв”ҖЕҹi, patlayв”Җв–’cв”Җв–’, parlayв”Җв–’cв”Җв–’ ve yanв”Җв–’cв”Җв–’ maddeler iв”ңДҹermeyen ve в”ңДҹevre saв”ҖЕҹlв”Җв–’в”ҖЕҹв”Җв–’ yв”ңГӮnв”ңв•қnden tehlike oluв”јЕҹturmayan atв”ңГӮlye, imalathane ile depolarв”Җв–’n yerleв”јЕҹmelere yakв”Җв–’n veya kolay ulaв”јЕҹв”Җв–’labilir yerlerinde yapв”Җв–’labildiв”ҖЕҹi alanlarв”Җв–’,\r\n\r\ng) Sosyal ve kв”ңв•қltв”ңв•қrel tesisler alanв”Җв–’: Toplumun kв”ңв•қltв”ңв•қrel faaliyetlerine yв”ңГӮnelik hizmet vermek в”ңв•қzere kв”ңв•қtв”ңв•қphane, halk eв”ҖЕҹitim merkezi, sergi salonu, sanat galerisi, mв”ңв•қze, konser, konferans, kongre salonlarв”Җв–’, sinema, tiyatro ve opera gibi fonksiyonlar ile sosyal yaв”јЕҹamв”Җв–’n niteliв”ҖЕҹini ve dв”ңв•қzeyini artв”Җв–’rmak amacв”Җв–’ ile toplumun faydalanacaв”ҖЕҹв”Җв–’ kreв”јЕҹ, kurs, yurt, в”ңДҹocuk yuvasв”Җв–’, yetiв”јЕҹtirme yurdu, yaв”јЕҹlв”Җв–’ ve engelli bakв”Җв–’mevi, rehabilitasyon merkezi, toplum merkezi, в”јЕҹefkat evleri gibi fonksiyonlarda hizmet vermek в”ңв•қzere ayrв”Җв–’lan kamu veya в”ңГӮzel mв”ңв•қlkiyetteki alanlarв”Җв–’,\r\n\r\nв”ҖЕҹ) Teknik altyapв”Җв–’ alanlarв”Җв–’: Kamu veya в”ңГӮzel sektв”ңГӮr tarafв”Җв–’ndan yapв”Җв–’lacak elektrik, petrol ve doв”ҖЕҹalgaz iletim hatlarв”Җв–’, reglaj istasyonlarв”Җв–’, su deposu, iв”ңДҹme ve kullanma suyu ile yer altв”Җв–’ ve yer в”ңв•қstв”ңв•қ her tв”ңв•қrlв”ңв•қ arв”Җв–’tma, kanalizasyon, atв”Җв–’k iв”јЕҹleme tesisleri, trafo, enerji daв”ҖЕҹв”Җв–’tв”Җв–’m merkezi, her tв”ңв•қrlв”ңв•қ enerji, ulaв”јЕҹtв”Җв–’rma, haberleв”јЕҹme gibi servislerin temini iв”ңДҹin yapв”Җв–’lan tesisler ile aв”ңДҹв”Җв–’k veya kapalв”Җв–’ otopark kullanв”Җв–’в”јЕҹlarв”Җв–’nв”Җв–’n yapв”Җв–’labileceв”ҖЕҹi alanlarв”Җв–’,\r\n\r\nh) Toplu iв”јЕҹyerleri: Bв”ңв•қyв”ңв•қk alan kullanв”Җв–’mв”Җв–’ gerektiren ticari iв”јЕҹletmeler, inв”јЕҹaat malzemesi, oto galeri, tarв”Җв–’msal в”ңв•қretim pazarlama, nakliyat ambarв”Җв–’, toptancв”Җв–’ hali, toptan ticaret, pazarlama ve depolama alanlarв”Җв–’, tв”Җв–’r ve kamyon parkв”Җв–’ ve benzeri tesisler ile в”ңДҹevre saв”ҖЕҹlв”Җв–’в”ҖЕҹв”Җв–’ yв”ңГӮnв”ңв•қnden gerekli tedbirler alв”Җв–’nmak kaydв”Җв–’yla mermer, hurda, teneke, kaв”ҖЕҹв”Җв–’t, plastik gibi maddelerin organize bir в”јЕҹekilde depolanmasв”Җв–’ ve iв”јЕҹlenmesine yв”ңГӮnelik faaliyetler ile bunlara iliв”јЕҹkin sosyal ve teknik altyapв”Җв–’ tesislerinin de yer aldв”Җв–’в”ҖЕҹв”Җв–’ alanlarв”Җв–’,\r\n\r\nifade eder.','',2,'2026-02-24 08:45:44',NULL,NULL),(3,NULL,'Eв”ҖЕҹitim','в”ңГ§ermik Belediyesi Etв”ңв•қt Merkezi 7 Gв”ңв•қn boyunca Saat 08:00 ile 22:00 saatleri arasв”Җв–’nda в”ңГӮв”ҖЕҹrencilerimize hizmet vermektedir.','uploads/guide/1772005739_etв”ңв•қt.jpeg',3,'2026-02-25 07:48:59',NULL,NULL),(4,NULL,'Vergi в”Җв–‘в”јЕҹlemleri','Emlak vergisi, Tв”ңв•қrkiye sв”Җв–’nв”Җв–’rlarв”Җв–’ iв”ңДҹinde bulunan bina, arsa ve araziler в”ңв•қzerinden alв”Җв–’nan vergi tв”ңв•қrв”ңв•қdв”ңв•қr.\r\n\r\nEmlak Vergisi Kanununda yer alan bina ve arazi vergisinin kapsamв”Җв–’, mв”ңв•қkellefi, mв”ңв•қkellefiyetin baв”јЕҹlamasв”Җв–’ ve sona ermesi, emlak vergisi bildirimi, emlak vergisinin matrah ve oranв”Җв–’, verginin в”ңГӮdeme zamanв”Җв–’, indirimli bina vergisi oranв”Җв–’ uygulamasв”Җв–’ gibi konular emlak vergisinin temel unsurlarв”Җв–’dв”Җв–’r.\r\n\r\nEmlak vergisi gayrimenkulв”ңв•қn kayв”Җв–’tlв”Җв–’ olduв”ҖЕҹu ilgili belediyeye в”ңГӮdenecek olup birinci taksiti mart, nisan ve mayв”Җв–’s aylarв”Җв–’nda, ikinci taksiti kasв”Җв–’m ayв”Җв–’nda olmak в”ңв•қzere iki eв”јЕҹit taksitte в”ңГӮdenebilmektedir.\r\n\r\nBina Vergisinin Kapsamв”Җв–’ Nedir?\r\n\r\nTв”ңв•қrkiye sв”Җв–’nв”Җв–’rlarв”Җв–’ iв”ңДҹinde bulunan binalar, Emlak Vergisi Kanunu hв”ңв•қkв”ңв•қmlerine gв”ңГӮre bina vergisine tabidir.\r\n\r\nArazi Vergisinin Kapsamв”Җв–’ Nedir?\r\n\r\nTв”ңв•қrkiye sв”Җв–’nв”Җв–’rlarв”Җв–’ iв”ңДҹinde bulunan arazi ve arsalar, Emlak Vergisi Kanunu hв”ңв•қkв”ңв•қmlerine gв”ңГӮre arazi vergisine tabidir.\r\n\r\nEmlak Vergisinin Kapsamв”Җв–’na Giren Bina, Arsa ve Arazi Tabirlerinin Kapsamв”Җв–’ Nedir?\r\n\r\nBina, yapв”Җв–’ldв”Җв–’в”ҖЕҹв”Җв–’ madde ne olursa olsun, gerek karada gerek su в”ңв•қzerindeki sabit inв”јЕҹaatlarв”Җв–’n hepsini kapsar. Yв”ңв•қzer havuzlar, sair yв”ңв•қzer yapв”Җв–’lar, в”ңДҹadв”Җв–’rlar ve nakil vasв”Җв–’talarв”Җв–’na takв”Җв–’lв”Җв–’p в”ңДҹekilebilen seyyar evler ve benzerleri bina sayв”Җв–’lmaz.\r\n\r\nBelediye sв”Җв–’nв”Җв–’rlarв”Җв–’ iв”ңДҹinde belediyece parsellenmiв”јЕҹ arazi arsa sayв”Җв–’lв”Җв–’r.\r\n\r\nArazi, sв”Җв–’nв”Җв–’rlarв”Җв–’ yeterli vasв”Җв–’talarla belirlenmiв”јЕҹ, yatay ve dв”ңв•қв”јЕҹey sв”Җв–’nв”Җв–’rlarв”Җв–’ bulunan yeryв”ңв•қzв”ңв•қ parв”ңДҹasв”Җв–’dв”Җв–’r. Aksine hв”ңв•қkв”ңв•қm olmadв”Җв–’kв”ңДҹa Emlak Vergisi Kanununda yer alan arazi tabiri arsalarв”Җв–’ da kapsar.\r\n\r\nBina ve Arazi Vergisinin Mв”ңв•қkellefi Kimlerdir?\r\n\r\nBina veya arazinin maliki, varsa intifa hakkв”Җв–’ sahibi, her ikisi de yoksa bina veya araziye malik gibi tasarruf edenlerdir. Bir bina veya araziye paylв”Җв–’ mв”ңв•қlkiyet halinde malik olanlar hisseleri oranв”Җв–’nda mв”ңв•қkelleftirler. Mв”ңв•қв”јЕҹterek mв”ңв•қlkiyette ise malikler vergiden mв”ңв•қteselsilen sorumludurlar.\r\n\r\nArazi Vergisinde в”Җв–‘stisnalar Nelerdir?\r\n\r\nMв”ңв•қkelleflerin bir belediye ve bu belediyenin mв”ңв•қcavir alan sв”Җв–’nв”Җв–’rlarв”Җв–’ iв”ңДҹinde bulunan arazisinin (arsalar hariв”ңДҹ) toplam vergi deв”ҖЕҹerinin 10.000 Tв”ңв•қrk lirasв”Җв–’ arazi vergisinden istisnadв”Җв–’r.\r\n\r\nBu hв”ңв•қkmв”ңв•қn uygulamasв”Җв–’nda mв”ңв•қkellef ile eв”јЕҹ ve velayet altв”Җв–’ndaki в”ңДҹocuklara ait arazi deв”ҖЕҹerleri toplu olarak dikkate alв”Җв–’nв”Җв–’r.\r\n\r\nв”Җв–‘stisna, hisseli arazide mв”ңв•қkelleflerin hisse miktarlarв”Җв–’ ayrв”Җв–’ ayrв”Җв–’ dikkate alв”Җв–’nmak suretiyle uygulanв”Җв–’r.\r\n\r\nBina ve Arazi Vergisinde Mв”ңв•қkellefiyet Ne Zaman Baв”јЕҹlar?\r\n\r\nEmlak Vergisi Kanununun 33 в”ңв•қncв”ңв•қ maddenin (1) ilв”ңГі (7) numaralв”Җв–’ fв”Җв–’kralarв”Җв–’nda yazв”Җв–’lв”Җв–’ vergi deв”ҖЕҹerini tadil eden sebeplerin doв”ҖЕҹmasв”Җв–’ halinde bu deв”ҖЕҹiв”јЕҹikliklerin meydana geldiв”ҖЕҹi, aynв”Җв–’ maddenin (8) numaralв”Җв–’ fв”Җв–’krasв”Җв–’nda yazв”Җв–’lв”Җв–’ halde ise bu duruma baв”ҖЕҹlв”Җв–’ olarak takdir iв”јЕҹleminin yapв”Җв–’ldв”Җв–’в”ҖЕҹв”Җв–’ tarihi,\r\nDв”ңГӮrt yв”Җв–’lda bir yapв”Җв–’lan takdir iв”јЕҹlemlerinde takdir iв”јЕҹleminin yapв”Җв–’ldв”Җв–’в”ҖЕҹв”Җв–’ tarihi,\r\nMuafiyetin sukut ettiв”ҖЕҹi tarihi,\r\ntakip eden bв”ңв•қtв”ңДҹe yв”Җв–’lв”Җв–’ndan itibaren baв”јЕҹlar.\r\n\r\nв”ңГ»rnek: Gayrimenkul 26/7/2025 tarihinde satв”Җв–’n alв”Җв–’nmв”Җв–’в”јЕҹ ise 31/12/2025 tarihine kadar, 15/11/2025 tarihinde satв”Җв–’n alв”Җв–’nmв”Җв–’в”јЕҹ ise satв”Җв–’n alma tarihinden itibaren в”ңв•қв”ңДҹ ay iв”ңДҹinde satв”Җв–’n alan tarafв”Җв–’ndan ilgili belediyeye emlak vergisi bildirimi verilmesi, her iki durumda da emlak vergisi mв”ңв•қkellefiyetinin 2026 yв”Җв–’lв”Җв–’ndan itibaren baв”јЕҹlamasв”Җв–’ gerekmektedir.\r\n\r\nBina ve Arazi Vergisinde Mв”ңв•қkellefiyet Ne Zaman Sona Erer?\r\n\r\nYanan, yв”Җв–’kв”Җв–’lan, tamamen kullanв”Җв–’lmaz hale gelen veya vergiye tabi iken muaflв”Җв–’k в”јЕҹartlarв”Җв–’nв”Җв–’ kazanan binalardan dolayв”Җв–’ mв”ңв•қkellefiyet, bu olaylarв”Җв–’n meydana geldiв”ҖЕҹi tarihi takip eden taksitten itibaren sona erer.\r\n\r\nOturulmasв”Җв–’ ve kullanв”Җв–’lmasв”Җв–’ kanunlarв”Җв–’n verdiв”ҖЕҹi yetkiye dayanв”Җв–’larak yasak edilen binalarв”Җв–’n vergileri, mв”ңв•қkelleflerce keyfiyetin vergi dairesine bildirilmesi veya vergi dairesince reГ”ГҮГ–sen tespit edilmesi в”ңв•қzerine, bu olaylarв”Җв–’n meydana geldiв”ҖЕҹi tarihlerden sonra gelen taksitlerden itibaren, bu hallerin devam ettiв”ҖЕҹi sв”ңв•қrece alв”Җв–’nmaz.\r\n\r\nArazi vergisinde mв”ңв•қkellefiyet, vergiye tabi iken muaflв”Җв–’k в”јЕҹartlarв”Җв–’nв”Җв–’ kazanan araziden dolayв”Җв–’ mв”ңв•қkellefiyet, bu olayв”Җв–’n meydana geldiв”ҖЕҹi tarihi takip eden taksitten itibaren sona erer.\r\n\r\nKanunlarв”Җв–’n verdiв”ҖЕҹi yetkiye dayanв”Җв–’larak tasarrufu yasak edilen arazinin vergisi, mв”ңв•қkelleflerce keyfiyetin vergi dairesine bildirilmesi veya vergi dairesince reГ”ГҮГ–sen tespit edilmesi в”ңв•қzerine, yasaklama tarihini izleyen taksitlerden itibaren bu hallerin devam ettiв”ҖЕҹi sв”ңв•қrece alв”Җв–’nmaz.\r\n\r\nDeprem, su basmasв”Җв–’, yangв”Җв–’n gibi tabii afetler sebebiyle yanan, yв”Җв–’kв”Җв–’lan binalarв”Җв–’n arsalarв”Җв–’na ait vergiler, bu olaylarв”Җв–’n vukua geldiв”ҖЕҹi tarihleri takip eden bв”ңв•қtв”ңДҹe yв”Җв–’lв”Җв–’ndan itibaren iki yв”Җв–’l sв”ңв•қre ile alв”Җв–’nmaz.\r\n\r\nв”ңВЈzerine bina yapв”Җв–’lan arsaya iliв”јЕҹkin arazi vergisi mв”ңв•қkellefiyeti, inв”јЕҹaatв”Җв–’n bittiв”ҖЕҹi yв”Җв–’lв”Җв–’ takip eden bв”ңв•қtв”ңДҹe yв”Җв–’lв”Җв–’ndan itibaren sona erer.\r\n\r\nBina ve Arazi Vergisinin Matrahв”Җв–’ Nedir?\r\n\r\nBina ve arazi vergisinin matrahв”Җв–’, bina ve arazi iв”ңДҹin Emlak Vergisi Kanunu hв”ңв•қkв”ңв•қmlerine gв”ңГӮre tespit olunan vergi deв”ҖЕҹeridir. Binaya sabit bir в”јЕҹekilde yerleв”јЕҹtirilmiв”јЕҹ olan her tв”ңв•қrlв”ңв•қ makine ve tesislere ait deв”ҖЕҹerler vergi matrahв”Җв–’na alв”Җв–’nmaz.\r\n\r\nEmlak Vergisinde Vergi Deв”ҖЕҹeri (Matrah) Nedir?\r\n\r\nVergi deв”ҖЕҹeri;\r\n\r\na) Arsa ve araziler iв”ңДҹin, Vergi Usul Kanununun asgari в”ңГӮlв”ңДҹв”ңв•қde birim deв”ҖЕҹer tespitine iliв”јЕҹkin hв”ңв•қkв”ңв•қmlerine gв”ңГӮre takdir komisyonlarв”Җв–’nca arsalar iв”ңДҹin her mahalle ve arsa sayв”Җв–’lacak parsellenmemiв”јЕҹ arazide her kв”ңГӮy iв”ңДҹin cadde, sokak veya deв”ҖЕҹer bakв”Җв–’mв”Җв–’ndan farklв”Җв–’ bв”ңГӮlgeler (turistik bв”ңГӮlgelerdeki cadde, sokak veya deв”ҖЕҹer bakв”Җв–’mв”Җв–’ndan farklв”Җв–’ olanlar ilgili valilerce tespit edilecek pafta, ada veya parseller), arazide her il veya ilв”ңДҹe iв”ңДҹin arazinin cinsi (kв”Җв–’raв”ңДҹ, taban, sulak) itibarв”Җв–’yla takdir olunan birim deв”ҖЕҹerlere gв”ңГӮre,\r\n\r\nb) Binalar iв”ңДҹin, Bakanlв”Җв–’в”ҖЕҹв”Җв–’mв”Җв–’z ve в”ңГ§evre в”јЕһehircilik ve в”Җв–‘klim Deв”ҖЕҹiв”јЕҹikliв”ҖЕҹi Bakanlв”Җв–’в”ҖЕҹв”Җв–’nca mв”ңв•қв”јЕҹtereken tespit ve ilв”ңГіn edilecek bina metrekare normal inв”јЕҹaat maliyetleri ile (a) bendinde belirtilen esaslara gв”ңГӮre bulunacak arsa veya arsa payв”Җв–’ deв”ҖЕҹeri esas alв”Җв–’narak Emlak Vergisi Kanununa gв”ңГӮre hazв”Җв–’rlanmв”Җв–’в”јЕҹ bulunan Tв”ңв•қzв”ңв•қk hв”ңв•қkв”ңв•қmlerinden yararlanв”Җв–’lmak suretiyle,\r\n\r\nhesaplanan bedeldir.\r\n\r\nVergi deв”ҖЕҹeri, mв”ңв•қkellefiyetin baв”јЕҹlangв”Җв–’в”ңДҹ yв”Җв–’lв”Җв–’nв”Җв–’ takip eden yв”Җв–’ldan itibaren her yв”Җв–’l, bir в”ңГӮnceki yв”Җв–’l vergi deв”ҖЕҹerinin Vergi Usul Kanunu hв”ңв•қkв”ңв•қmleri uyarв”Җв–’nca aynв”Җв–’ yв”Җв–’l iв”ңДҹin tespit edilen yeniden deв”ҖЕҹerleme oranв”Җв–’nв”Җв–’n yarв”Җв–’sв”Җв–’ nispetinde artв”Җв–’rв”Җв–’lmasв”Җв–’ suretiyle bulunur.\r\n\r\nEmlak Vergisi Kanununa gв”ңГӮre mв”ңв•қkellefiyet tesisi gereken hallerde vergi deв”ҖЕҹerinin hesaplanmasв”Җв–’nda, Vergi Usul Kanununa gв”ңГӮre belirlenen arsa ve arazi birim deв”ҖЕҹerleri, takdir iв”јЕҹleminin yapв”Җв–’ldв”Җв–’в”ҖЕҹв”Җв–’ yв”Җв–’lв”Җв–’ takip eden ikinci yв”Җв–’ldan baв”јЕҹlamak suretiyle her yв”Җв–’l, bir в”ңГӮnceki yв”Җв–’l birim deв”ҖЕҹerinin, Vergi Usul Kanunu hв”ңв•қkв”ңв•қmleri uyarв”Җв–’nca aynв”Җв–’ yв”Җв–’l iв”ңДҹin tespit edilen yeniden deв”ҖЕҹerleme oranв”Җв–’nв”Җв–’n yarв”Җв–’sв”Җв–’ nispetinde artв”Җв–’rв”Җв–’lmasв”Җв–’ suretiyle dikkate alв”Җв–’nв”Җв–’r.\r\n\r\nEmlak Vergisinde Tarh ve Tahakkuk в”Җв–‘в”јЕҹlemi Nasв”Җв–’l Yapв”Җв–’lв”Җв–’r?\r\n\r\nBina ve arazi vergisi, ilgili belediye tarafв”Җв–’ndan;\r\n\r\nDв”ңГӮrt yв”Җв–’lda bir defa olmak в”ңв•қzere takdir iв”јЕҹlemlerinin yapв”Җв–’ldв”Җв–’в”ҖЕҹв”Җв–’ yв”Җв–’lв”Җв–’ takip eden bв”ңв•қtв”ңДҹe yв”Җв–’lв”Җв–’nв”Җв–’n ocak ve в”јЕҹubat aylarв”Җв–’nda,\r\nKanunun 33 в”ңв•қncв”ңв•қ maddesinin (1) ilв”ңГі (7) numaralв”Җв–’ fв”Җв–’kralarв”Җв–’nda yazв”Җв–’lв”Җв–’ vergi deв”ҖЕҹerini tadil eden sebeplerle bildirim verilmesi icap eden hallerde, vergi deв”ҖЕҹerini tadil eden sebeplerin meydana geldiв”ҖЕҹi bв”ңв•қtв”ңДҹe yв”Җв–’lв”Җв–’nв”Җв–’ takip eden yв”Җв–’lв”Җв–’n ocak ayв”Җв–’ iв”ңДҹinde, vergi deв”ҖЕҹerini tadil eden sebep bв”ңв•қtв”ңДҹe yв”Җв–’lв”Җв–’nв”Җв–’n son в”ңв•қв”ңДҹ ayв”Җв–’ iв”ңДҹinde vuku bulmuв”јЕҹ ve bildirim, vergi deв”ҖЕҹerini tadil eden sebebin meydana geldiв”ҖЕҹi bв”ңв•қtв”ңДҹe yв”Җв–’lв”Җв–’nв”Җв–’ takip eden yв”Җв–’lda verilmiв”јЕҹ ise bildirimin verildiв”ҖЕҹi tarihte,\r\nKanunun  33 в”ңв•қncв”ңв•қ maddesinin (8) numaralв”Җв–’ fв”Җв–’krasв”Җв–’nda yazв”Җв–’lв”Җв–’ hallerde, takdir iв”јЕҹlemlerinin yapв”Җв–’ldв”Җв–’в”ҖЕҹв”Җв–’ bв”ңв•қtв”ңДҹe yв”Җв–’lв”Җв–’nв”Җв–’ takip eden yв”Җв–’lв”Җв–’n ocak ve в”јЕҹubat aylarв”Җв–’nda,\r\nEmlak Vergisi Kanununa gв”ңГӮre hesaplanan vergi deв”ҖЕҹeri esas alв”Җв–’narak yв”Җв–’llв”Җв–’k olarak tarh olunur.\r\n\r\nBildirim posta ile gв”ңГӮnderilmiв”јЕҹ ise vergi, bildirim verme sв”ңв•қresinin son gв”ңв•қnв”ңв•қnв”ңв•қ takip eden yedi gв”ңв•қn iв”ңДҹinde tarh olunur. Bu suretle tarh olunan vergiler, tarh edilen tarihte tahakkuk etmiв”јЕҹ sayв”Җв–’lв”Җв–’r ve mв”ңв•қkellefe bir yazв”Җв–’ ile bildirilir.\r\n\r\nYapв”Җв–’lan tarh ve tahakkuku takip eden yв”Җв–’llarda, Emlak Vergisi Kanununa gв”ңГӮre tespit edilen vergi deв”ҖЕҹeri в”ңв•қzerinden hesaplanan bina ve arazi vergisi, her bв”ңв•қtв”ңДҹe yв”Җв–’lв”Җв–’nв”Җв–’n baв”јЕҹв”Җв–’ndan itibaren o yв”Җв–’l iв”ңДҹin tahakkuk etmiв”јЕҹ sayв”Җв–’lв”Җв–’r.\r\n\r\nBir il veya ilв”ңДҹe sв”Җв–’nв”Җв–’rlarв”Җв–’ iв”ңДҹerisinde birden fazla belediye olmasв”Җв–’ halinde, belediye ve mв”ңв•қcavir alan sв”Җв–’nв”Җв–’rlarв”Җв–’ dв”Җв–’в”јЕҹв”Җв–’nda bulunan bina ve araziye ait emlak vergisini tarha yetkili olacak belediye, ilgili valiler tarafв”Җв–’ndan belirlenir.\r\n\r\nBina ve Arazi Vergisi Oranlarв”Җв–’ Nedir?\r\n\r\nEmlak Vergisi Kanununa gв”ңГӮre;\r\n\r\nBina vergisinin oranв”Җв–’ meskenlerde binde 1, diв”ҖЕҹer binalarda binde 2,\r\nArazide binde 1, arsalarda ise binde 3Г”ГҮГ–tв”ңв•қr.\r\nBina, arsa ve arazilere iliв”јЕҹkin vergi oranlarв”Җв–’ bв”ңв•қyв”ңв•қkв”јЕҹehir belediye sв”Җв–’nв”Җв–’rlarв”Җв–’ ve mв”ңв•қcavir alanlar iв”ңДҹinde %100 artв”Җв–’rв”Җв–’mlв”Җв–’ uygulanв”Җв–’r.\r\n\r\n \r\n\r\nKonut\r\n\r\nв”Җв–‘в”јЕҹyeri\r\n\r\nArsa\r\n\r\nArazi\r\n\r\nBв”ңв•қyв”ңв•қkв”јЕҹehir belediyesi dв”Җв–’в”јЕҹв”Җв–’ndaki yerlerde\r\n\r\nBinde 1\r\n\r\nBinde 2\r\n\r\nBinde 3\r\n\r\nBinde 1\r\n\r\nBв”ңв•қyв”ңв•қkв”јЕҹehir belediye sв”Җв–’nв”Җв–’rlarв”Җв–’ ve mв”ңв•қcavir alanlarda\r\n\r\nBinde 2\r\n\r\nBinde 4\r\n\r\nBinde 6\r\n\r\nBinde 2\r\n\r\nYeni inв”јЕҹa edilen bina veya binalarв”Җв–’n vergisi, arsasв”Җв–’nв”Җв–’n (veya arsa payв”Җв–’nв”Җв–’n) vergisinden az olamaz. Bu kriter/в”јЕҹart, binalarв”Җв–’n inв”јЕҹalarв”Җв–’nв”Җв–’n sona erdiв”ҖЕҹi yв”Җв–’lв”Җв–’ takip eden bв”ңв•қtв”ңДҹe yв”Җв–’lв”Җв–’ndan itibaren dв”ңГӮrt yв”Җв–’l uygulanв”Җв–’r.','',4,'2026-02-25 07:50:37',NULL,NULL);
