INSERT INTO `road_stops` VALUES (8,14,'Kaya Silв”ңв•қetleri Baв”јЕҹlangв”Җв–’cв”Җв–’',150,'Saв”ҖЕҹ tarafв”Җв–’nв”Җв–’zdaki kayalara bakв”Җв–’n, sanki bir insan dizisi gibi duruyorlar deв”ҖЕҹil mi? Efsaneye gв”ңГӮre burasв”Җв–’ bir gelin alayв”Җв–’dв”Җв–’r.'),(9,14,'Zirve Manzara Noktasв”Җв–’',100,'Harika bir manzara! Buradan tв”ңв•қm в”ңГ§ermik ayaklarв”Җв–’nв”Җв–’zв”Җв–’n altв”Җв–’nda. Derinden bir nefes alв”Җв–’n.'),(10,15,'Vadi Giriв”јЕҹi',200,'Kanyona girmek в”ңв•қzeresiniz. Havanв”Җв–’n serinlediв”ҖЕҹini hissetmeye baв”јЕҹlayacaksв”Җв–’nв”Җв–’z.'),(11,15,'Ana в”јЕһelale Gв”ңГӮrв”ңв•қв”јЕҹ Alanв”Җв–’',50,'в”Җв–‘в”јЕҹte o muazzam ses! в”јЕһeyhandede в”јЕһelalesi tв”ңв•қm ihtiв”јЕҹamв”Җв–’ ile karв”јЕҹв”Җв–’nв”Җв–’zda.'),(12,16,'Tarihi Sinek Kв”ңГӮprв”ңв•қsв”ңв•қ',100,'Bu eski kв”ңГӮprв”ңв•қ, Sinek в”ңГ§ayв”Җв–’\'nв”Җв–’n en karakteristik yapв”Җв–’larв”Җв–’ndan biridir. Fotoв”ҖЕҹraf в”ңДҹekmek iв”ңДҹin durabilirsiniz.'),(13,16,'в”јЕһelale Yanв”Җв–’ Piknik Alanв”Җв–’',100,'Burada bir mola verip Sinek в”ңГ§ayв”Җв–’\'nв”Җв–’n buz gibi suyunda karpuz в”ңДҹatlatmaya ne dersiniz?'),(14,17,'Antik Basamaklar',50,'Binlerce yв”Җв–’l в”ңГӮnce buradan kervanlarв”Җв–’n geв”ңДҹtiв”ҖЕҹini hayal edin. Bu taв”јЕҹ basamaklar o gв”ңв•қnlerden kalma.'),(15,17,'Ticaret Yolu Kavв”јЕҹaв”ҖЕҹв”Җв–’',100,'Burasв”Җв–’ doв”ҖЕҹu ile batв”Җв–’yв”Җв–’ baв”ҖЕҹlayan ana damarlardan biriydi.'),(16,18,'Gв”ңГӮzeler Mevkii',100,'Suyun yeraltв”Җв–’ndan kaynadв”Җв–’в”ҖЕҹв”Җв–’ noktaya в”ңДҹok yaklaв”јЕҹtв”Җв–’nв”Җв–’z. Su burada en saf halindedir.'),(17,18,'Maв”ҖЕҹaralar Bв”ңГӮlgesi',150,'Solunuzdaki yamaв”ңДҹlarda keв”јЕҹfedilmeyi bekleyen birв”ңДҹok gizemli maв”ҖЕҹara bulunuyor.');
