INSERT INTO `services` VALUES (5,'в”ңГ§ermik Belediyesi Melike Belkв”Җв–’s Kaplв”Җв–’calarв”Җв–’nв”Җв–’ Yenileyerek Modern Hale Getirdik.','2016 YILINDA Hв”Җв–‘ZMETE GELDв”Җв–‘в”ҖЕһв”Җв–‘Mв”Җв–‘Z Gв”ңВЈNDEN в”Җв–‘Tв”Җв–‘BAREN ESKв”Җв–‘ HALDE OLAN KAPLICALARIMIZI MODERN HALE GETв”Җв–‘REREK HALKMIZIN Hв”Җв–‘ZMETв”Җв–‘NE SUNDUK.\r\n\r\n',1,'uploads/projects/1772008365_saat kulesi.jpg',NULL,NULL),(6,'Doв”ҖЕҹalgaz ','в”јЕһimdiye kadar kв”ңГӮmв”ңв•қr ve diв”ҖЕҹer katв”Җв–’ atв”Җв–’klar ile ilв”ңДҹemiz halkв”Җв–’nв”Җв–’n в”Җв–’sв”Җв–’nma ve diв”ҖЕҹer ticari faaliyet alanlarв”Җв–’nda kullandв”Җв–’в”ҖЕҹв”Җв–’ kв”ңГӮtв”ңв•қ koku ve hava kirliliв”ҖЕҹine neden olan yakв”Җв–’t tв”ңв•қrlerini son vermek iв”ңДҹin enerji ve tabii kaynaklar bakanlв”Җв–’в”ҖЕҹв”Җв–’ ile yapmв”Җв–’в”јЕҹ olduв”ҖЕҹumuz gв”ңГӮrв”ңв•қв”јЕҹmeler neticesinde halkв”Җв–’mв”Җв–’za sв”ңГӮz verdiв”ҖЕҹimiz gibi doв”ҖЕҹal gaz alt yapв”Җв–’ hizmetlerini tamamlayarak ilв”ңДҹe halkв”Җв–’mв”Җв–’zв”Җв–’n hizmetine sunduk.',1,'uploads/projects/1772011283_WhatsApp Image 2019-03-19 at 15.54.38.jpeg',NULL,NULL),(7,'в”Җв–‘в”ңДҹme Suyu','в”Җв–‘lв”ңДҹe merkezimizde 50 yв”Җв–’lв”Җв–’ aв”јЕҹkв”Җв–’n sв”ңв•қredir kullanв”Җв–’mв”Җв–’ gerв”ңДҹekleв”јЕҹtirilen saв”ҖЕҹlв”Җв–’ksв”Җв–’z aspes borular ile hane ve iв”јЕҹ yerlerine giden iв”ңДҹme suyu в”јЕҹebekemizin alt yapв”Җв–’sв”Җв–’nв”Җв–’n tamamв”Җв–’nв”Җв–’ Diyarbakв”Җв–’r Bв”ңв•қyв”ңв•қkв”јЕҹehir Belediyesine baв”ҖЕҹlв”Җв–’ Dв”Җв–‘SKв”Җв–‘ genel Mв”ңв•қdв”ңв•қrlв”ңв•қв”ҖЕҹв”ңв•қ ile yapв”Җв–’lan mutabakatlar sonucunda iв”ңДҹme suyu в”јЕҹebekesini yenileterek halkв”Җв–’mв”Җв–’zв”Җв–’n hizmetine sunduk.\r\n\r\n',1,'uploads/projects/1772011493_hikaye kapak.jpg',NULL,NULL),(8,'Hizmet Binasв”Җв–’','1960 yв”Җв–’lв”Җв–’ndan bu yana bir в”ңДҹok belediye baв”јЕҹkanв”Җв–’ tarafв”Җв–’ndan kullanв”Җв–’lan gв”ңв•қnв”ңв•қmв”ңв•қz в”јЕҹartlarв”Җв–’ndan halkв”Җв–’mв”Җв–’za hizmet konusunda eksik kalan hizmet binamв”Җв–’zв”Җв–’ daha modern hale getirerek yeniledik.\r\n\r\n',1,'',NULL,NULL),(9,'Sokak Saв”ҖЕҹlв”Җв–’klaв”јЕҹtв”Җв–’rma','в”Җв–‘lв”ңДҹemizin Merkez tarihi в”ңДҹarв”јЕҹв”Җв–’sв”Җв–’nda hizmet veren iв”јЕҹyerlerinin gв”ңГӮrв”ңв•қntв”ңв•қ kirliв”ҖЕҹi oluв”јЕҹturduв”ҖЕҹu bu doв”ҖЕҹrultuda daha modern hizmet verecek iв”јЕҹ yerleri haline getirerek Diyarbakв”Җв–’r Bв”ңв•қyв”ңв•қkв”јЕҹehir Belediyesinin katkв”Җв–’larв”Җв–’ ile halkв”Җв–’mв”Җв–’z esnaflarв”Җв–’ caddesinin в”ңДҹehresini deв”ҖЕҹiв”јЕҹtirdik.',1,'',NULL,NULL),(10,'Kuruyemiв”јЕҹ Pazarв”Җв–’','в”Җв–‘lв”ңДҹemizde yв”Җв–’llardв”Җв–’r hizmet veren kuruyemiв”јЕҹ Pazar esnaflarв”Җв–’ ile yapв”Җв–’lan istiв”јЕҹare sonucunda esnaf ve sanatkarlarв”Җв–’mв”Җв–’zв”Җв–’n talepleri neticesinde в”ңГ§ermik Belediyesi olarak yapmв”Җв–’в”јЕҹ olduв”ҖЕҹumuz proje ile iв”јЕҹ yerlerini daha konforlu hale getirip esnaf ve halkв”Җв–’mв”Җв–’zв”Җв–’n hizmetine sunduk.',1,'',NULL,NULL),(11,'Halв”Җв–’ Saha','Baв”јЕҹta genв”ңДҹlerimiz ve tв”ңв•қm spor severerler iв”ңДҹin yapmв”Җв–’в”јЕҹ olduв”ҖЕҹumuz halв”Җв–’ saha projelerimizi spor toto ile imzalamв”Җв–’в”јЕҹ olduв”ҖЕҹumuz protokollerle 2 adet ilв”ңДҹe Merkezimizde 10 adet Kв”Җв–’rsal Mahallelerimizde olmak в”ңв•қzere 12 adet halв”Җв–’ sahanв”Җв–’n yapв”Җв–’mв”Җв–’nв”Җв–’ gerв”ңДҹekleв”јЕҹtirdik.',1,'',NULL,NULL),(12,'Iв”јЕҹв”Җв–’klandв”Җв–’rma','в”Җв–‘lв”ңДҹemiz Tepe Mahallesi Belediye hizmet binasв”Җв–’ в”ңГӮnв”ңв•қnden Meslek yв”ңв•қksek okulu mevkisine kadar alt yapв”Җв–’ ve в”ңв•қst yapв”Җв–’ в”ңДҹalв”Җв–’в”јЕҹmalarв”Җв–’nв”Җв–’ bitirmiв”јЕҹ olduв”ҖЕҹumuz caddemize modern cadde-sokak aydв”Җв–’nlatmalarв”Җв–’ ile ilв”ңДҹemize ayrв”Җв–’ bir hava kattв”Җв–’k.\r\n\r\n',1,'',NULL,NULL),(13,'Park ve Bahв”ңДҹeler','Gв”ңГӮreve geldiв”ҖЕҹimiz 2016 yв”Җв–’lв”Җв–’ndan yapmв”Җв–’в”јЕҹ olduв”ҖЕҹumuz izlenim sonucunda ilв”ңДҹemizin bв”ңв•қyв”ңв•қk eksikliklerinden olan в”ңДҹocuk oyun alanв”Җв–’ , yetiв”јЕҹkin spor alanв”Җв–’ ve yeв”јЕҹil alanlarв”Җв–’n eksikliв”ҖЕҹi gв”ңГӮrв”ңв•қlmв”ңв•қв”јЕҹtв”ңв•қr. Bu eksikliklerin tamamlanmasв”Җв–’ iв”ңДҹin uzun yв”Җв–’llardв”Җв–’r ilв”ңДҹemize kв”ңГӮtв”ңв•қ bir imaj veren katв”Җв–’ atв”Җв–’k toplama alanв”Җв–’nв”Җв–’n yerini deв”ҖЕҹiв”јЕҹtirerek mesire alanв”Җв–’na в”ңДҹevirdik.Bunun akabininde ilв”ңДҹemizin farklв”Җв–’ noktalarв”Җв–’na park ve bahв”ңДҹeler kurararak , gerekli personeller ile gerek temizlik gerek gв”ңв•қvenlik в”ңГӮnlemleri alarak halkв”Җв–’mв”Җв–’zв”Җв–’n hizmetine sunduk.',1,'',NULL,NULL),(14,'TOKв”Җв–‘','Uzun yв”Җв–’llardв”Җв–’r talep edilip bir tв”ңв•қrlв”ңв•қ ilв”ңДҹemize gelmesi hayal olan toki konutlarв”Җв–’ iв”ңДҹin dв”ңГӮnemin в”ңГ§evre в”јЕһehircilik Bakanв”Җв–’ Sn.Murat KURUM ile yapв”Җв–’lan ikili gв”ңГӮrв”ңв•қв”јЕҹmeler sonucunda ilв”ңДҹe merkezimizde 158 adet Toplu Konut inв”јЕҹaasв”Җв–’nв”Җв–’ ilв”ңДҹemize kazandв”Җв–’rdв”Җв–’k.',1,'',NULL,NULL),(15,'Kв”ңв•қltв”ңв•қr ve Sanat','Gв”ңв•қnв”ңв•қmв”ңв•қzв”ңв•қn genв”ңДҹliв”ҖЕҹine verdiв”ҖЕҹimiz в”ңГӮnem neticesinde eksiklik olarak gв”ңГӮrв”ңв•қlen fuar ve etkinlik alanв”Җв–’nda в”ңГӮnemli в”ңДҹalв”Җв–’в”јЕҹmalar yaparak bir в”ңДҹok etkinliв”ҖЕҹe в”ңГӮncв”ңв•қlв”ңв•қk ettik. в”ңГ§ermik Kitap Fuarв”Җв–’ Konser ve aktiviteler в”јЕһehir gezileri',1,'',NULL,NULL),(16,'Kasaplar Sebze Pazarв”Җв–’','Kasaplar bв”ңГӮlgesi ve sebze pazarв”Җв–’nв”Җв–’n alt yapв”Җв–’ ve в”ңв•қst yapв”Җв–’larв”Җв–’nв”Җв–’ tamamlayarak в”ңв•қstв”ңв•қnв”ңв•қn tamamв”Җв–’nв”Җв–’ yaв”ҖЕҹmur gв”ңв•қneв”јЕҹ ve olumsuz hava в”јЕҹartlarв”Җв–’na karв”јЕҹв”Җв–’ kapatв”Җв–’lmasв”Җв–’nв”Җв–’ saв”ҖЕҹladв”Җв–’k.',1,'',NULL,NULL),(17,'Devlet Hastanesi','в”Җв–‘lв”ңДҹemizde yв”Җв–’llardв”Җв–’r vatandaв”јЕҹlarв”Җв–’mв”Җв–’zв”Җв–’n kanayan yanasв”Җв–’ olan hastane ihtiyacв”Җв–’nв”Җв–’ karв”јЕҹв”Җв–’lamak iв”ңДҹin в”ңДҹevre ilв”ңДҹe ve illere giderek hastalв”Җв–’klarв”Җв–’na derman arв”Җв–’yorlardв”Җв–’. Halkв”Җв–’mв”Җв–’zв”Җв–’n bu sorununun в”ңДҹв”ңГӮzв”ңв•қmв”ңв•қ iв”ңДҹin в”Җв–‘lв”ңДҹemize yeni bir devlet hastanesi yapв”Җв–’lmasв”Җв–’ iв”ңДҹin ilgili kurumlarla yapв”Җв–’lan istiв”јЕҹareler sonucunda ilв”ңДҹemize Devlet hastanesi kazandв”Җв–’rdв”Җв–’k.',1,'',NULL,NULL),(18,'Gelincik Daв”ҖЕҹв”Җв–’ , Dravв”јЕҹa Yolu','Gelincikdaв”ҖЕҹв”Җв–’ , dravв”јЕҹa yolunu tamamen parke taв”јЕҹв”Җв–’ yaparak konumda yaв”јЕҹayan halkв”Җв–’mв”Җв–’z ve ilв”ңДҹe dв”Җв–’в”јЕҹв”Җв–’ndan turizm seyahatine gelen misafirlerimiz iв”ңДҹin ulaв”јЕҹв”Җв–’ma kolay hale getirdik.',1,'',NULL,NULL),(19,'Tarihi Saray Hamamв”Җв–’','Tarihi hamamв”Җв–’zв”Җв–’ atв”Җв–’l durumundan kurtararak yeniden restorasyon sв”ңв•қrecini baв”јЕҹlattв”Җв–’k. Tarihi geв”ңДҹmiв”јЕҹimize yakв”Җв–’в”јЕҹв”Җв–’r bir hale getirdik.',1,'',NULL,NULL),(20,'Hayvan Pazarв”Җв–’ ve Mezbahane','',1,'',NULL,NULL),(21,'в”Җв–‘lв”ңДҹemiz giriв”јЕҹinde Siverek - Diyarbakв”Җв–’r yolu kavв”јЕҹaв”ҖЕҹв”Җв–’nda saat kulesi.','',1,'',NULL,NULL),(22,'Fen ve Sanat Yapв”Җв–’larв”Җв–’','Kв”Җв–’rsal mahallerimizde yollarв”Җв–’n bozulmasв”Җв–’na sebep olan dere yataklarв”Җв–’ yaв”ҖЕҹmur sularв”Җв–’nв”Җв–’ deв”јЕҹarj edebilmek iв”ңДҹin sanat yapв”Җв–’larв”Җв–’ ( dв”ңв•қz boru,menfez ) в”ңДҹalв”Җв–’в”јЕҹmalarв”Җв–’ yaparak kв”Җв–’rsal mahallelerimizin sorunlarв”Җв–’nв”Җв–’ в”ңДҹв”ңГӮzв”ңв•қme kavuв”јЕҹturduk.',0,'',NULL,NULL),(23,'Sв”Җв–’cak Asfalt ve tretuar','в”Җв–‘lв”ңДҹe merkezinde sв”Җв–’cak asfalt ve tretuar в”ңДҹalв”Җв–’в”јЕҹmalarв”Җв–’ yaparak ana yollar в”ңв•қzerindeki iklimsel sorunlarв”Җв–’ tamamen ortadan kaldв”Җв–’rdв”Җв–’k.',0,'',NULL,NULL),(24,'Kamulaв”јЕҹtв”Җв–’rma','Merkez mahallerimizde araв”ңДҹlarв”Җв–’n girmekte sorun yaв”јЕҹadв”Җв–’в”ҖЕҹв”Җв–’ , bazв”Җв–’ bв”ңГӮlgelerde yollarв”Җв–’n tamamen tв”Җв–’kanmasв”Җв–’na sebep olan ev ve arsalarв”Җв–’ kamulaв”јЕҹtв”Җв–’rma yaparak halkв”Җв–’mв”Җв–’zв”Җв–’n hizmetine sunduk.',0,'',NULL,NULL),(25,'Kilitli Parke Taв”јЕҹв”Җв–’','в”Җв–‘lв”ңДҹemiz merkezinde alt yapв”Җв–’ ve в”ңв•қst yapв”Җв–’ в”ңДҹalв”Җв–’в”јЕҹmalarв”Җв–’nв”Җв–’ tamamladв”Җв–’в”ҖЕҹв”Җв–’mв”Җв–’z cadde ve sokaklarв”Җв–’mв”Җв–’zda kilitli parke taв”јЕҹв”Җв–’ dв”ңГӮв”јЕҹeyerek vatandaв”јЕҹlarв”Җв–’mв”Җв–’zв”Җв–’n hizmetine sunduk. Kв”Җв–’rsal mahallelerimizin bir в”ңДҹoв”ҖЕҹunda gв”ңГӮrв”ңв•қlen eksiklikler sonucunda kilitli parke taв”јЕҹв”Җв–’ yol yapв”Җв–’m iв”јЕҹlemlerimize baв”јЕҹladв”Җв–’k ve devam ediyoruz.',0,'',NULL,NULL);
