INSERT INTO `settings` VALUES (1,'mayor_name','в”јЕһehmus KARAMEHMETOв”ҖЕһLU','2026-02-27 12:33:51'),(2,'mayor_title','в”ңГ§ermik Belediye Baв”јЕҹkanв”Җв–’ ','2026-02-27 12:34:44'),(3,'mayor_image','assets/img/baskan.png','2026-02-24 10:40:48'),(4,'site_name','в”ңГ§ermik Belediyesi','2026-02-27 10:55:43'),(5,'site_email','admin@cermil.bel.tr','2026-02-27 10:58:33'),(6,'site_phone','4124612001','2026-02-27 11:30:13'),(7,'site_address','Tepe Mah.','2026-02-27 09:21:36'),(8,'copyright_text','Rotamв”Җв–’z в”ңГ§ermik','2026-02-27 10:54:52'),(9,'facebook_link','https://www.facebook.com/p/%C3%87ermik-Belediyesi-100064935810446/?locale=tr_TR','2026-02-27 10:51:30'),(10,'instagram_link','https://www.instagram.com/cermikbelediyesi/','2026-02-27 10:51:30'),(11,'youtube_link','https://www.youtube.com/@cermikbelediyesi','2026-02-27 10:51:30'),(12,'twitter_link','https://x.com/cermikbld/status/1923747974338748880','2026-02-27 10:51:30'),(13,'kvkk_text','1. в”Җв–‘в”јЕҹlenen Kiв”јЕҹisel Verileriniz\r\nUygulamayв”Җв–’ kullanв”Җв–’mв”Җв–’nв”Җв–’z sв”Җв–’rasв”Җв–’nda aв”јЕҹaв”ҖЕҹв”Җв–’daki verileriniz iв”јЕҹlenebilir:\r\n\r\nKimlik Bilgileri: Ad, soyadв”Җв–’.\r\n\r\nв”Җв–‘letiв”јЕҹim Bilgileri: E-posta adresi, telefon numarasв”Җв–’.\r\n\r\nKonum Bilgileri: Cihazв”Җв–’nв”Җв–’zв”Җв–’n GPS verileri (yakв”Җв–’nв”Җв–’ndaki tarihi yerleri gв”ңГӮstermek ve bildirim gв”ңГӮndermek amacв”Җв–’yla).\r\n\r\nв”Җв–‘в”јЕҹlem Gв”ңв•қvenliв”ҖЕҹi: IP adresi, uygulama giriв”јЕҹ-в”ңДҹв”Җв–’kв”Җв–’в”јЕҹ kayв”Җв–’tlarв”Җв–’, cihaz modeli.\r\n\r\n2. Kiв”јЕҹisel Verilerin в”Җв–‘в”јЕҹlenme Amaв”ңДҹlarв”Җв–’\r\nKiв”јЕҹisel verileriniz, в”ңГ§ermikГ”ГҮГ–in tanв”Җв–’tв”Җв–’mв”Җв–’ ve belediye hizmetlerinin iyileв”јЕҹtirilmesi amacв”Җв–’yla в”јЕҹu durumlarda iв”јЕҹlenir:\r\n\r\nUygulama iв”ңДҹerisinde kullanв”Җв–’cв”Җв–’ hesabв”Җв–’ oluв”јЕҹturulmasв”Җв–’.\r\n\r\nYerel Rehber hizmeti kapsamв”Җв–’nda konumunuza yakв”Җв–’n tarihi ve turistik yerlerin (в”ңГ»rn: Hanbaв”јЕҹв”Җв–’ Camii, Karakaya Hanв”Җв–’) gв”ңГӮsterilmesi.\r\n\r\nBelediye duyurularв”Җв–’, etkinlikler ve turistik bilgilendirmeler hakkв”Җв–’nda bildirim gв”ңГӮnderilmesi.\r\n\r\nUygulama performansв”Җв–’nв”Җв–’n в”ңГӮlв”ңДҹв”ңв•қlmesi ve kullanв”Җв–’cв”Җв–’ deneyiminin geliв”јЕҹtirilmesi.\r\n\r\n3. Kiв”јЕҹisel Verilerin Aktarв”Җв–’lmasв”Җв–’\r\nKiв”јЕҹisel verileriniz, yasal yв”ңв•қkв”ңв•қmlв”ңв•қlв”ңв•қklerin yerine getirilmesi amacв”Җв–’yla yetkili kamu kurum ve kuruluв”јЕҹlarв”Җв–’ ile paylaв”јЕҹв”Җв–’labilecek olup; bunun dв”Җв–’в”јЕҹв”Җв–’nda в”ңв•қв”ңДҹв”ңв•қncв”ңв•қ taraflarla ticari amaв”ңДҹla paylaв”јЕҹв”Җв–’lmamaktadв”Җв–’r.\r\n\r\n4. Kiв”јЕҹisel Veri Toplamanв”Җв–’n Yв”ңГӮntemi ve Hukuki Sebebi\r\nVerileriniz, uygulamayв”Җв–’ telefonunuza indirmeniz, kayв”Җв–’t formunu doldurmanв”Җв–’z ve uygulama izinlerini (Konum, Bildirim vb.) onaylamanв”Җв–’z suretiyle tamamen dijital ortamda toplanmaktadв”Җв–’r. в”Җв–‘в”јЕҹleme faaliyeti, KVKKГ”ГҮГ–nв”Җв–’n 5. maddesinde yer alan \"в”Җв–‘lgili kiв”јЕҹinin aв”ңДҹв”Җв–’k rв”Җв–’zasв”Җв–’\" ve \"Veri sorumlusunun hukuki yв”ңв•қkв”ңв•қmlв”ңв•қlв”ңв•қв”ҖЕҹв”ңв•қ\" sebeplerine dayanв”Җв–’r.\r\n\r\n5. Veri Sahiplerinin Haklarв”Җв–’\r\nKVKKГ”ГҮГ–nв”Җв–’n 11. maddesi uyarв”Җв–’nca BelediyeГ”ГҮГ–ye baв”јЕҹvurarak;\r\n\r\nVerilerinizin iв”јЕҹlenip iв”јЕҹlenmediв”ҖЕҹini в”ңГӮв”ҖЕҹrenme,\r\n\r\nв”Җв–‘в”јЕҹlenmiв”јЕҹse bilgi talep etme,\r\n\r\nEksik veya yanlв”Җв–’в”јЕҹ iв”јЕҹlenmiв”јЕҹse dв”ңв•қzeltilmesini isteme,\r\n\r\nVerilerinizin silinmesini veya yok edilmesini isteme haklarв”Җв–’na sahipsiniz.','2026-02-27 10:51:30'),(14,'cookie_policy','в”ңГ§ermik Belediyesi (Г”ГҮВЈBelediyeГ”ГҮГҳ) olarak, mobil uygulamamв”Җв–’z (Г”ГҮВЈYerel RehberГ”ГҮГҳ) в”ңв•қzerinden kullanв”Җв–’cв”Җв–’ deneyiminizi geliв”јЕҹtirmek, hizmetlerimizi optimize etmek ve size в”ңГӮzel iв”ңДҹerikler sunmak amacв”Җв–’yla в”ңДҹerezler ve benzeri takip teknolojileri kullanmaktayв”Җв–’z.1. в”ңГ§erez Nedir?в”ңГ§erezler, bir uygulamayв”Җв–’ ziyaret ettiв”ҖЕҹinizde veya kullandв”Җв–’в”ҖЕҹв”Җв–’nв”Җв–’zda cihazв”Җв–’nв”Җв–’za (akв”Җв–’llв”Җв–’ telefon, tablet) kaydedilen kв”ңв•қв”ңДҹв”ңв•қk metin dosyalarв”Җв–’ veya veri parв”ңДҹacв”Җв–’klarв”Җв–’dв”Җв–’r. Bu teknolojiler, cihazв”Җв–’nв”Җв–’zв”Җв–’ tanв”Җв–’mamв”Җв–’za ve uygulama iв”ңДҹindeki tercihlerinizi (dil seв”ңДҹimi, giriв”јЕҹ bilgileri vb.) hatв”Җв–’rlamamв”Җв–’za yardв”Җв–’mcв”Җв–’ olur.2. Uygulamamв”Җв–’zda Kullanв”Җв–’lan в”ңГ§erez Tв”ңв•қrleriв”ңГ§erez Tв”ңв•қrв”ңв•қAв”ңДҹв”Җв–’klamaZorunlu в”ңГ§erezlerUygulamanв”Җв–’n temel fonksiyonlarв”Җв–’nв”Җв–’n (giriв”јЕҹ yapma, gв”ңв•қvenlik doв”ҖЕҹrulama) в”ңДҹalв”Җв–’в”јЕҹmasв”Җв–’ iв”ңДҹin gereklidir.в”Җв–‘в”јЕҹlevsel в”ңГ§erezlerDil tercihiniz veya \"Beni Hatв”Җв–’rla\" gibi kiв”јЕҹiselleв”јЕҹtirilmiв”јЕҹ ayarlarв”Җв–’nв”Җв–’zв”Җв–’ kaydeder.Performans в”ңГ§erezleriUygulamanв”Җв–’n hangi bв”ңГӮlв”ңв•қmlerinin daha в”ңДҹok ziyaret edildiв”ҖЕҹini analiz etmemizi saв”ҖЕҹlar (Google Analytics vb.).Konum в”ңГ§erezleriSize en yakв”Җв–’n tarihi mekanв”Җв–’ veya belediye hizmet noktasв”Җв–’nв”Җв–’ gв”ңГӮstermek iв”ңДҹin coв”ҖЕҹrafi verilerinizi iв”јЕҹler.3. в”ңГ§erezlerin Kullanв”Җв–’m Amaв”ңДҹlarв”Җв–’Kiв”јЕҹisel verileriniz, aв”јЕҹaв”ҖЕҹв”Җв–’daki amaв”ңДҹlar doв”ҖЕҹrultusunda в”ңДҹerezler aracв”Җв–’lв”Җв–’в”ҖЕҹв”Җв–’yla iв”јЕҹlenmektedir:Uygulamanв”Җв–’n gв”ңв•қvenli ve hatasв”Җв–’z в”ңДҹalв”Җв–’в”јЕҹmasв”Җв–’nв”Җв–’ saв”ҖЕҹlamak.в”ңГ§ermik iв”ңДҹindeki konumunuza gв”ңГӮre (в”ңГ»rn: Karakaya Kв”ңГӮyв”ңв•қ civarв”Җв–’ndaysanв”Җв–’z) ilgili tanв”Җв–’tв”Җв–’m ve rehber iв”ңДҹeriklerini sunmak.Kullanв”Җв–’cв”Җв–’ alв”Җв–’в”јЕҹkanlв”Җв–’klarв”Җв–’nв”Җв–’ analiz ederek uygulamanв”Җв–’n ara yв”ңв•қzв”ңв•қnв”ңв•қ geliв”јЕҹtirmek.4. в”ңГ§erez Tercihlerinin Yв”ңГӮnetimiUygulamamв”Җв–’zв”Җв–’n kullanв”Җв–’mв”Җв–’ sв”Җв–’rasв”Җв–’nda в”ңДҹerezlere verdiв”ҖЕҹiniz izinleri dilediв”ҖЕҹiniz zaman yв”ңГӮnetebilirsiniz:Cihaz Ayarlarв”Җв–’: Mobil cihazв”Җв–’nв”Җв–’zв”Җв–’n ayarlar kв”Җв–’smв”Җв–’ndan \"Uygulamalar > Yerel Rehber > в”Җв–‘zinler\" yolunu izleyerek konum ve veri toplama izinlerini kapatabilirsiniz.Uygulama в”Җв–‘в”ңДҹi Ayarlar: Uygulama iв”ңДҹerisindeki \"Ayarlar\" menв”ңв•қsв”ңв•қnden bildirim ve konum bazlв”Җв–’ servisleri devre dв”Җв–’в”јЕҹв”Җв–’ bв”Җв–’rakabilirsiniz.Not: Zorunlu в”ңДҹerezlerin devre dв”Җв–’в”јЕҹв”Җв–’ bв”Җв–’rakв”Җв–’lmasв”Җв–’, uygulamanв”Җв–’n bazв”Җв–’ в”ңГӮzelliklerinin в”ңДҹalв”Җв–’в”јЕҹmamasв”Җв–’na neden olabilir.5. в”Җв–‘letiв”јЕҹimв”ңГ§erez politikamв”Җв–’z hakkв”Җв–’ndaki sorularв”Җв–’nв”Җв–’z iв”ңДҹin в”ңГ§ermik Belediyesi ile [E-posta Adresi/в”Җв–‘letiв”јЕҹim Formu] в”ңв•қzerinden iletiв”јЕҹime geв”ңДҹebilirsiniz.','2026-02-27 10:51:30'),(86,'explore_desc','Tarihin Sв”Җв–’caklв”Җв–’в”ҖЕҹв”Җв–’ Doв”ҖЕҹanв”Җв–’n Saklв”Җв–’ Yв”ңв•қzв”ңв•қ ','2026-02-27 11:05:29'),(87,'explore_desc_en','The Warmth of History, The Hidden Face of Nature','2026-02-27 11:05:29'),(113,'last_pharmacy_fetch','1772195169','2026-02-27 12:26:09');
